import React, { useState } from 'react';

interface AssetTreePanelProps {
  categories: string[];
  selectedCategory: string;
  onSelectCategory: (category: string) => void;
}

const AssetTreePanel: React.FC<AssetTreePanelProps> = ({ categories, selectedCategory, onSelectCategory }) => {
  const [expanded, setExpanded] = useState(true);

  return (
    <div className="w-full max-w-[250px] rounded-3xl border border-slate-200 bg-white shadow-sm">
      <div className="border-b border-slate-200 px-5 py-4">
        <div className="text-sm font-semibold text-slate-900">Asset Categories</div>
      </div>

      <div className="h-[calc(100vh-240px)] overflow-auto px-3 py-4">
        <button
          type="button"
          onClick={() => setExpanded((value) => !value)}
          className="flex w-full items-center justify-between rounded-2xl px-4 py-3 text-left text-sm font-medium text-slate-900 transition hover:bg-slate-50"
        >
          <span>All Assets</span>
          <span className="text-slate-400">{expanded ? '▾' : '▸'}</span>
        </button>

        {expanded && (
          <div className="mt-3 space-y-1 pl-4">
            {categories.map((category) => {
              const selected = selectedCategory === category;
              return (
                <button
                  key={category}
                  type="button"
                  onClick={() => onSelectCategory(category)}
                  className={`flex w-full items-center rounded-2xl px-4 py-3 text-sm text-slate-700 transition ${
                    selected ? 'bg-slate-100 text-slate-900' : 'hover:bg-slate-50'
                  }`}
                >
                  <span className="mr-2 text-slate-400">•</span>
                  <span className="truncate">{category}</span>
                </button>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

export default AssetTreePanel;
